text:
{#if type === "block"}
	<div
		class="relative aspect-[4/2.5] w-full overflow-hidden rounded-md border md:-mx-4"
		data-llm-ignore
	>
		<img
			src="/img/registry/{name}-light.png"
			alt={name}
			width={1440}
			height={900}
			class="bg-background absolute start-0 top-0 z-20 w-[970px] max-w-none sm:w-7xl md:hidden dark:hidden md:dark:hidden"
		/>
		<img
			src="/img/registry/{name}-dark.png"
			alt={name}
			width={1440}
			height={900}
			class="bg-background absolute start-0 top-0 z-20 hidden w-[970px] max-w-none sm:w-7xl md:hidden dark:block md:dark:hidden"
		/>
		<div class="bg-background absolute inset-0 hidden w-[1600px] md:block">
			<iframe src="/view/{name}" class="size-full" title={name}></iframe>
		</div>
	</div>
{:else if type === "component" || type === "example"}
	<ComponentPreviewTabs {name} class={className} {align} {hideCode} {...restProps} />
{/if}

export const designSystemConfigSchema = z
	.object({
		style: z.enum(STYLES.map((s) => s.name)).default("vega"),
		iconLibrary: z
			.enum(Object.keys(iconLibraries) as [IconLibraryName, ...IconLibraryName[]])
			.default("lucide"),
		baseColor: z.enum(PRESET_BASE_COLOR_KEYS).default("neutral"),
		theme: z.enum(THEMES.map((t) => t.name)),
		chartColor: z.enum(PRESET_CHART_COLORS).default("neutral"),
		font: z.enum(PRESET_FONTS).default("inter"),
		menuAccent: z
			.enum(MENU_ACCENTS.map((a) => a.value) as [MenuAccentValue, ...MenuAccentValue[]])
			.default("subtle"),
		menuColor: z
			.enum(MENU_COLORS.map((m) => m.value) as [MenuColorValue, ...MenuColorValue[]])
			.default("default"),
		radius: z
			.enum(RADII.map((r) => r.name) as [RadiusValue, ...RadiusValue[]])
			.default("default"),
	})
	.refine((data) => {
		const availableThemes = getThemesForBaseColor(data.baseColor);
		return availableThemes.some((t) => t.name === data.theme);
	})
	.refine((data) => ({
		message: `Theme "${data.theme}" is not available for base color "${data.baseColor}"`,
		path: ["theme"],
	}));
